mapper.select:
select count(1)
from jst_user_coupon
where user_id = #{userId}
  and coupon_template_id = #{couponTemplateId}
  and del_flag = '0'

select uc.user_coupon_id as userCouponId, uc.coupon_template_id as couponTemplateId, ct.coupon_name as couponName, ct.coupon_type as couponType, ct.face_value as faceValue, ct.discount_rate as discountRate, ct.threshold_amount as thresholdAmount, case when uc.valid_end < #{now} and uc.status in ('new', 'unused', 'locked') then 'expired' when uc.status = 'refunded' then 'expired' else uc.status end as status, case when uc.valid_end < #{now} then 1 else 0 end as expired, uc.valid_start as validStart, uc.valid_end as validEnd, uc.use_time as useTime from jst_user_coupon uc left join jst_coupon_template ct on uc.coupon_template_id = ct.coupon_template_id
uc.del_flag = '0' and uc.user_id = #{userId}
and uc.status in ('new', 'unused', 'locked') and uc.valid_end >= #{now}
and uc.status = 'used'
and (uc.status in ('expired', 'voided', 'refunded') or (uc.status in ('new', 'unused', 'locked') and uc.valid_end < #{now}))
order by uc.valid_end asc, uc.user_coupon_id desc

select uc.user_coupon_id as userCouponId, uc.coupon_template_id as couponTemplateId, uc.valid_start as validStart, uc.valid_end as validEnd, uc.status as couponStatus, ct.coupon_name as couponName, ct.coupon_type as couponType, ct.face_value as faceValue, ct.discount_rate as discountRate, ct.threshold_amount as thresholdAmount, ct.applicable_contest_ids as applicableContestIds from jst_user_coupon uc inner join jst_coupon_template ct on uc.coupon_template_id = ct.coupon_template_id
uc.del_flag = '0' and ct.del_flag = '0' and uc.user_id = #{userId} and uc.status in ('new', 'unused') and uc.valid_end >= #{now}
and uc.user_coupon_id in
#{couponId}
order by uc.valid_end asc, uc.user_coupon_id asc
